// ======================================================
// Build Execution Queue
// Reads: Filters + Providers
// Mode: Run Once for All Items
// ======================================================

// ------------------------------------------------------
// Read Inputs
// ------------------------------------------------------

const filters = $('ReadFilters').all();
const providers = $('ReadProviders').all();

// ------------------------------------------------------
// Helper
// ------------------------------------------------------

function isEnabled(value) {
    if (typeof value === "boolean") return value;
    if (typeof value === "number") return value === 1;

    return String(value || "")
        .trim()
        .toLowerCase() === "true";
}

// ------------------------------------------------------
// Build Queue
// ------------------------------------------------------

const queue = [];
const createdAt = new Date().toISOString();

let counter = 1;

for (const filterItem of filters) {

    const filter = filterItem.json;

    // Skip disabled filters (optional)
    if (
        filter.Enabled !== undefined &&
        !isEnabled(filter.Enabled)
    ) {
        continue;
    }

    for (const providerItem of providers) {

        const provider = providerItem.json;

        // Skip disabled providers
        if (!isEnabled(provider.Enabled)) {
            continue;
        }

        queue.push({

            json: {

                requestId: `REQ-${Date.now()}-${counter++}`,

                createdAt,

                status: "PENDING",

                provider: provider.Provider,

                providerType: provider.Type,


                keyword: filter.Keyword,

                location: filter.Location || "Any",

                experience: filter.Experience || "Any",

                remote: filter.Remote || "Any",

                jobType: filter["Job Type"] || "Any"

            }

        });

    }

}

// ------------------------------------------------------
// Sort by Provider Priority
// ------------------------------------------------------


// ------------------------------------------------------
// Log
// ------------------------------------------------------

console.log(`Filters : ${filters.length}`);
console.log(`Providers : ${providers.length}`);
console.log(`Requests : ${queue.length}`);

// ------------------------------------------------------
// Return
// ------------------------------------------------------

return queue;

