const normalized = [];

for (const item of items) {

    const response = item.json;

    if (
        response.status !== "SUCCESS" ||
        !Array.isArray(response.jobs)
    ) {
        continue;
    }

    for (const job of response.jobs) {

        // ----------------------------------
        // Work Mode
        // ----------------------------------

        let workMode = "Unknown";

        if (job.workMode) {

            const mode = job.workMode.toLowerCase();

            if (mode.includes("remote")) {
                workMode = "Remote";
            }

            else if (
                mode.includes("office") ||
                mode.includes("onsite")
            ) {
                workMode = "Onsite";
            }

            else if (
                mode.includes("hybrid") ||
                mode.includes("onsite or remote")
            ) {
                workMode = "Hybrid";
            }
        }

        // ----------------------------------
        // Salary Parsing
        // ----------------------------------

        let currency = null;
        let salaryMin = null;
        let salaryMax = null;
        let equity = null;

        const rawSalary = job.salary ?? null;

        if (rawSalary) {

            if (rawSalary.includes("₹")) currency = "INR";
            else if (rawSalary.includes("$")) currency = "USD";
            else if (rawSalary.includes("€")) currency = "EUR";
            else if (rawSalary.includes("£")) currency = "GBP";

            const salaryPart = rawSalary.split("•")[0].trim();

            const values = salaryPart.match(/[\d,.]+[KLM]?/gi);

            function parseAmount(value) {

                if (!value) return null;

                value = value.replace(/,/g, "");

                let multiplier = 1;

                if (/K$/i.test(value)) {
                    multiplier = 1000;
                    value = value.slice(0, -1);
                }

                else if (/L$/i.test(value)) {
                    multiplier = 100000;
                    value = value.slice(0, -1);
                }

                else if (/M$/i.test(value)) {
                    multiplier = 1000000;
                    value = value.slice(0, -1);
                }

                return Math.round(parseFloat(value) * multiplier);
            }

            if (values?.length > 0)
                salaryMin = parseAmount(values[0]);

            if (values?.length > 1)
                salaryMax = parseAmount(values[1]);

            if (rawSalary.includes("•")) {
                equity = rawSalary.split("•")[1].trim();
            }
        }

        // ----------------------------------
        // Normalize
        // ----------------------------------

        normalized.push({

            requestId: response.requestId,

            provider: response.provider,

            providerType: "Search",

            jobId: job.jobId ?? null,

            title: job.title ?? "",

            company: null,

            location: job.location ?? null,

            workMode,

            employmentType: null,

            experience: job.expierence ?? null,

            salary: {

                currency,

                min: salaryMin,

                max: salaryMax,

                equity,

                raw: rawSalary,

            },

            description: null,

            skills: [],

            tags: [],

            recruiterActive:
                job.recruiterActive ?? false,

            postedAt:
                job.posted ?? null,

            applyUrl:
                job.url,

            companyLogo: null,

            sourceUrl:
                job.url,

            status: "FOUND",

            createdAt:
                new Date().toISOString(),

            metadata: {}

        });

    }
}

return normalized.map(job => ({ json: job }));

