// ------------------------------------------------------
// Read Inputs
// ------------------------------------------------------

const filters = $('ReadFilters').all();
const providers = $('ReadProviders').all();

// ------------------------------------------------------
// Internshala Profiles
// ------------------------------------------------------

const internshalaProfiles = [
    "Artificial Intelligence (AI)",
    "AI Agent Development",
    "Prompt Engineering",
    "Backend Development",
    "Full Stack Development",
    "Front End Development",
    "Web Development",
    "Software Development",
    "Javascript Development",
    "Node.js Development",
    "Angular.js Development",
    "Software Testing"
];

// ------------------------------------------------------
// Helper
// ------------------------------------------------------

function isEnabled(value) {
    if (typeof value === "boolean") return value;
    if (typeof value === "number") return value === 1;

    return String(value || "")
        .trim()
        .toLowerCase() === "true";
}

// ------------------------------------------------------
// Build Queue
// ------------------------------------------------------

const queue = [];
const createdAt = new Date().toISOString();

let counter = 1;

for (const providerItem of providers) {

    const provider = providerItem.json;

    // Skip disabled providers
    if (!isEnabled(provider.Enabled)) {
        continue;
    }

    // ==================================================
    // Internshala
    // One request per profile
    // ==================================================

    if (provider.Provider === "Internshala") {

        for (const profile of internshalaProfiles) {

            queue.push({

                json: {

                    requestId: `REQ-${Date.now()}-${counter++}`,

                    createdAt,

                    status: "PENDING",

                    provider: provider.Provider,

                    providerType: provider.Type,

                    keyword: profile,

                    location: "Any",

                    experience: "0 - 1 yrs",

                    remote: "Any",

                    jobType: "Any"

                }

            });

        }

        continue;
    }

    // ==================================================
    // All Other Providers
    // Use Filters Sheet
    // ==================================================

    for (const filterItem of filters) {

        const filter = filterItem.json;

        // Skip disabled filters
        if (
            filter.Enabled !== undefined &&
            !isEnabled(filter.Enabled)
        ) {
            continue;
        }

        queue.push({

            json: {

                requestId: `REQ-${Date.now()}-${counter++}`,

                createdAt,

                status: "PENDING",

                provider: provider.Provider,

                providerType: provider.Type,

                keyword: filter.Keyword,

                location: filter.Location || "Any",

                experience: filter.Experience || "Any",

                remote: filter.Remote || "Any",

                jobType: filter["Job Type"] || "Any"

            }

        });

    }

}

// ------------------------------------------------------
// Log
// ------------------------------------------------------

console.log(`Filters : ${filters.length}`);
console.log(`Providers : ${providers.length}`);
console.log(`Requests : ${queue.length}`);

// ------------------------------------------------------
// Return
// ------------------------------------------------------

return queue;
